//! Phase 1B.1 pilot: thin shim over [`tracepilot_tauri_bindings::specta_exports::export`].
//!
//! Run via `pnpm gen:bindings` (or
//! `cargo run -p tracepilot-tauri-bindings --bin gen-bindings` from the
//! repo root). Emits `packages/client/src/generated/bindings.ts`.
//!
//! The heavy lifting lives inside the lib crate so that the hidden
//! per-command macros generated by `#[specta::specta]` (which are only
//! reachable from within the defining crate) can be resolved by
//! `collect_commands!`.

use std::path::PathBuf;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Resolve output path relative to the crate manifest so `cargo run` from
    // the repo root, a crate dir, or an IDE all work identically.
    let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    let out_path = manifest_dir
        .join("..")
        .join("..")
        .join("packages")
        .join("client")
        .join("src")
        .join("generated")
        .join("bindings.ts");

    tracepilot_tauri_bindings::specta_exports::export(&out_path)?;

    println!("wrote {}", out_path.display());
    Ok(())
}
